return ['domain'=>NULL,'plural-forms'=>'nplurals=2; plural=(n != 1);','language'=>'es_CL','project-id-version'=>'TranslatePress Multilingual','pot-creation-date'=>'2026-05-25T19:29:27+03:00','po-revision-date'=>'2026-02-08 00:59:44+0000','x-generator'=>'TranslatePress build (community + OpenRouter), 2026-05-25','messages'=>['Please update the TranslatePress - Multilingual plugin to version %1$s or higher to ensure %2$s functions correctly.'=>'Actualiza el plugin TranslatePress - Multilingual a la versión %1$s o superior para asegurar que %2$s funcione correctamente.','Please install and activate the TranslatePress - Multilingual plugin'=>'Instala y activa el plugin TranslatePress - Multilingual.','Install & Activate'=>'Instalar y activar','Please update TranslatePress - Multilingual to version %2$s or newer. Your currently installed version of TranslatePress - Multilingual is no longer compatible with the current version of %1$s.'=>'Actualiza TranslatePress - Multilingual a la versión %2$s o más reciente. La versión actualmente instalada de TranslatePress - Multilingual ya no es compatible con la versión actual de %1$s.','All TranslatePress functionalities are disabled until then.'=>'Todas las funcionalidades de TranslatePress estarán desactivadas hasta entonces.','Update Now'=>'Actualizar ahora','This TranslatePress add-on has been migrated to the main plugin and is no longer used. You can delete it.'=>'Esta extensión de TranslatePress se ha migrado al plugin principal y ya no se usa. Puedes borrarla.','<strong>TranslatePress</strong> requires at least PHP version 5.6.20+ to run. It is the <a href="%s">minimum requirement of the latest WordPress version</a>. Please contact your server administrator to update your PHP version.'=>'<strong>TranslatePress</strong> necesita, al menos, la versión 5.6.20+ para funcionar. Es el <a href="%s">requisito mínimo de la última versión de WordPress</a>. Por favor, contacta con el administrador del servidor para actualizar la versión de PHP.','Advanced'=>'Avanzado','Settings saved.'=>'Ajustes guardados.','Are you sure you want to remove this item?'=>'¿Seguro que quieres eliminar este elemento?','Remove'=>'Eliminar','Add'=>'Agregar','Select...'=>'Seleccionar...','[%s] Low TranslatePress AI Words'=>'[%s] Quedan pocas palabras de TranslatePress AI','upgrade your plan or get extra AI Words'=>'actualiza tu plan u obtén palabras de IA extra','upgrade your plan'=>'actualiza tu plan','TranslatePress AI words are running low on your site.'=>'Las palabras de TranslatePress AI se están agotando en tu sitio.','Current status: %s words remaining'=>'Estado actual: %s palabras restantes','Once the remaining AI words run out, automatic translation through TranslatePress AI will be paused.'=>'Una vez que se agoten las palabras de IA restantes, la traducción automática mediante TranslatePress AI se pausará.','To continue translating your content, please %1$s over at %2$s'=>'Para continuar traduciendo tu contenido, por favor %1$s en %2$s','Manage Notification: %s'=>'Administrar notificación: %s','There is a new version of %1$s available. %2$sView version %3$s details%4$s or %5$supdate now%6$s.'=>'Hay una nueva versión de %1$s disponible. %2$sVer los detalles de la versión %3$s %4$s o %5$sactualiza ahora%6$s.','There is a new version of %1$s available. %2$sView version %3$s details%4$s.'=>'Hay una nueva versión de %1$s disponible. %2$sVer los detalles de la versión %3$s%4$s.','To enable updates, please %1$senter your license key%2$s. Need a license key? %3$sPurchase one now%4$s.'=>'Para habilitar las actualizaciones, por favor %1$singresa tu clave de licencia%2$s. ¿Necesitas una clave de licencia? %3$sCompra una ahora%4$s.','To enable updates, please go to the %1$slicense page%2$s and check that you have a valid license.'=>'Para habilitar las actualizaciones, ve a la %1$spágina de licencia%2$s y verifica que tengas una licencia válida.','To enable updates, your licence needs to be renewed. Please go to the %1$sTranslatePress Account%2$s page and login to renew.'=>'Para habilitar las actualizaciones, tu licencia debe renovarse. Ve a la página %1$sTranslatePress Account%2$s e inicia sesión para renovarla.','You do not have permission to install plugin updates'=>'No tienes permisos para instalar actualizaciones de plugins','Error'=>'Error','Your TranslatePress license key is invalid or missing.'=>'Tu clave de licencia de TranslatePress no es válida o no existe.','Your license key expired on %s.'=>'Tu clave de licencia caduca el %s.','Your license key has been disabled.'=>'Tu licencia ha sido desactivada.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Tu clave de licencia está desactivada para esta URL. Reactívala desde <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Administrar sitios.','<p><strong>License key mismatch.</strong> The license you entered doesn’t match the TranslatePress version you have installed.</p><p>Please check that you’ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>La clave de licencia no coincide.</strong> La licencia que ingresaste no coincide con la versión de TranslatePress que tienes instalada.</p><p>Por favor, verifica que hayas instalado la versión correcta para tu licencia desde tu cuenta de TranslatePress.</p>','If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'Si tienes solo el plugin gratuito instalado pero agregaste una licencia de pago, instala el plugin de pago desde tu cuenta de TranslatePress.','Your license key has reached its activation limit.'=>'Tu clave de licencia ha llegado a su límite de activaciones.','Upgrade your plan to add more sites. %1$sUpgrade now%2$s'=>'Actualiza tu plan para agregar más sitios. %1$sActualizar ahora%2$s','This website is already activated under a free license. Each website can only use one free license.'=>'Este sitio web ya está activado con una licencia gratuita. Cada sitio web solo puede usar una licencia gratuita.','An error occurred, please try again.'=>'Hubo un error. Por favor, inténtalo otra vez.','You have successfully activated your license'=>'Has activado tu licencia con éxito','Others'=>'Otros','Restrict by Language'=>'Restringir por idioma','Exclude from Language'=>'Excluir del idioma','Restrict element to language'=>'Restringir elemento a un idioma','Show this element only in one language.'=>'Muestra este elemento solo en un idioma.','Enable translation'=>'Activar traducción','Allow translation to the corresponding language only if the content is written in the default language.'=>'Permitir la traducción al idioma correspondiente solo si el contenido está escrito en el idioma por defecto.','Select language'=>'Seleccionar idioma','Choose in which language to show this element.'=>'Elige en qué idioma se mostrará este elemento.','Exclude element from language'=>'Excluir elemento del idioma','Exclude this element from specific languages.'=>'Excluye este elemento de idiomas específicos.','Select languages'=>'Seleccionar idiomas','Choose from which languages to exclude this element.'=>'Elige de qué idiomas se excluirá este elemento.','This element will still be visible when you are translating your website through the Translation Editor.'=>'Este elemento todavía estará visible cuando estés traduciendo tu web usando el editor de traducciones.','The content of this element should be written in the default language.'=>'El contenido de este elemento debe estar escrito en el idioma por defecto.','<strong>TranslatePress</strong> encountered SQL errors. <a href="%s" title="View TranslatePress SQL Errors">Check out the errors</a>.'=>'<strong>TranslatePress</strong> ha encontrado errores SQL. <a href="%s" title="Ver errores SQL de TranslatePress">Revisa los errores</a>.','Automatic translation has been disabled.'=>'La traducción automática ha sido desactivada.','Dismiss this notice.'=>'Descartar este aviso.','Logged errors'=>'Errores registrados','These are the most recent 5 errors logged by TranslatePress:'=>'Estos son los 5 errores más recientes registrados en TranslatePress:','Yes'=>'Sí','Why are these errors occuring'=>'¿Por qué están ocurriendo estos errores?','If TranslatePress detects something wrong when executing queries on your database, it may disable the Automatic Translation feature in order to avoid any extra charging by Google/DeepL. Automatic Translation needs to be manually turned on, after you solve the issues.'=>'Si TranslatePress detecta algún error al ejecutar consultas en tu base de datos, puede desactivar la característica de traducción automática para evitar cualquier cobro adicional por parte de Google/DeepL. Es necesario activar manualmente la traducción automática después de que hayas solucionado los problemas.','The SQL errors detected can occur for various reasons including missing tables, missing permissions for the SQL user to create tables or perform other operations, problems after site migration or changes to SQL server configuration.'=>'Los errores SQL detectados pueden ocurrir por varios motivos: falta de tablas, falta de permisos del usuario SQL para crear tablas o realizar otras operaciones, problemas posteriores a la migración del sitio o cambios en la configuración del servidor SQL.','What you can do in this situation'=>'¿Qué puedes hacer en esta situación?','Plan A.'=>'Plan A.','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL settings. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Ve a Ajustes -> TranslatePress -> pestaña General y Guardar ajustes. Esto regenerará las tablas que utilizan tus ajustes actuales de SQL. Comprueba si no ocurren más errores al navegar en tu web en un idioma traducido. Fíjate en las marcas de tiempo de los errores para asegurarte de que no estás viendo los errores antiguos. Solo se muestran los 5 errores más recientes.','Plan B.'=>'Plan B.','If your problem isn\'t solved, try the following steps:'=>'Si no se resuelve tu problema, prueba los siguientes pasos:','Create a backup of your database'=>'Crea una copia de seguridad de tu base de datos.','Create a copy of each translation table where you encounter errors. You can copy the table within the same database (trp_dictionary_en_us_es_es_COPY for example) -- perform this step only if you want to keep the current translations'=>'Crea una copia de cada tabla de traducción donde encuentres errores. Puedes copiar la tabla dentro de la misma base de datos (por ejemplo, trp_dictionary_en_us_es_es_COPY). Realiza este paso solo si quieres conservar las traducciones actuales.','Remove the trouble tables by executing the DROP function on them'=>'Elimina las tablas problemáticas ejecutando en ellas la función DROP.','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL server.'=>'Ve a Ajustes -> TranslatePress -> pestaña General y Guardar ajustes. Esto regenerará las tablas que utilizan tu servidor SQL actual.','Copy the relevant content from the duplicated tables (trp_dictionary_en_us_es_es_COPY for example) in the newly generated table (trp_dictionary_en_us_es_es) -- perform this step only if you want to keep the current translations'=>'Copia el contenido relevante de las tablas duplicadas (por ejemplo, trp_dictionary_en_us_es_es_COPY) en la nueva tabla generada (trp_dictionary_en_us_es_es). Realiza este paso solo si quieres conservar las traducciones actuales.','Test it to see if everything is working. If something went wrong, you can restore the backup that you\'ve made at the first step. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Pruébalo para ver si todo está funcionando. Si algo salió mal, puedes restaurar la copia de seguridad que hiciste en el primer paso. Comprueba si no ocurren más errores al navegar en tu web en un idioma traducido. Fíjate en las marcas de tiempo de los errores para asegurarte de que no estás viendo los errores antiguos. Solo se muestran los 5 errores más recientes.','Plan C.'=>'Plan C.','If your problem still isn\'t solved, try asking your hosting about your errors. The most common issue is missing permissions for the SQL user, such as the Create Tables permission.'=>'Si todavía no se resuelve tu problema, intenta consultar a tu proveedor de alojamiento sobre tus errores. El problema más común es la falta de permisos del usuario SQL, como el permiso para crear tablas.','Could not install. Try again from <a href="%s" >Plugins Dashboard.</a>'=>'No se pudo instalar. Inténtalo de nuevo desde el <a href="%s" >escritorio de plugins</a>.','Active'=>'Activo','Permission denied.'=>'Permiso denegado.','Invalid nonce.'=>'Nonce no válido.','Settings scope unknown.'=>'Alcance de los ajustes desconocido.','Legacy disabled.'=>'Elemento heredado desactivado.','Language Switcher'=>'Conmutador de idioma','Change language to %s'=>'Cambiar idioma a %s','Automatic Translation'=>'Traducción automática','DeepL'=>'DeepL','Unsupported languages'=>'Idiomas no compatibles','The selected automatic translation engine does not provide support for these languages.<br>You can still manually translate pages in these languages using the Translation Editor.'=>'El motor de traducción automática seleccionado no proporciona compatibilidad con estos idiomas.<br>Todavía puedes traducir páginas de forma manual en estos idiomas utilizando el editor de traducciones.','API key validation failed.'=>'Ha fallado la validación de la clave API.','API key verification was successful.'=>'La verificación de la clave API se ha realizado correctamente.','Please enter your Google Translate key.'=>'Escribe tu clave de Google Translate.','Please enter your DeepL API key.'=>'Escribe tu clave de API de DeepL.','Not TranslatePress onboarding page.'=>'No es la página de configuración inicial de TranslatePress.','Step %s does not exist'=>'El paso %s no existe','Welcome'=>'Bienvenida','Add Languages'=>'Agregar idiomas','Enable Addons'=>'Habilitar complementos','Finalize'=>'Finalizar','Exit Setup'=>'Salir de la configuración','Upgrade'=>'Actualizar','Nothing here'=>'No hay nada aquí','Your <strong>TranslatePress</strong> license is missing or invalid. <br/>Please %1$sregister your copy%2$s to enable automatic website translation via TranslatePress AI, premium addons, automatic updates and support. Need a license key? %3$sPurchase one now%4$s'=>'Tu licencia de <strong>TranslatePress</strong> no existe o no es válida. <br/>Por favor, %1$sregistra tu copia%2$s para habilitar la traducción automática del sitio web mediante TranslatePress AI, complementos premium, actualizaciones automáticas y soporte. ¿Necesitas una clave de licencia? %3$sCompra una ahora%4$s','Your <strong>TranslatePress</strong> license will expire on %1$s. Please %2$sRenew Your Licence%3$s to continue receiving access to automatic translations via TP AI, premium addons, product downloads and automatic updates. %4$sRenew Now%5$s'=>'Tu licencia de <strong>TranslatePress</strong> vencerá el %1$s. Por favor, %2$srenueva tu licencia%3$s para seguir recibiendo acceso a traducciones automáticas mediante TP AI, complementos premium, descargas de productos y actualizaciones automáticas. %4$sRenovar ahora%5$s','Error: '=>'Error:','Something went wrong, please try again.'=>'Algo ha salido mal, por favor, inténtalo de nuevo.','Your <strong>TranslatePress</strong> license has expired. <br/>Please %1$sRenew Your Licence%2$s to continue receiving access to automatic translations via TranslatePress AI, premium addons, product downloads, and automatic updates. %3$sRenew now %4$s'=>'Tu licencia de <strong>TranslatePress</strong> ha vencido. <br/>Por favor, %1$srenueva tu licencia%2$s para seguir recibiendo acceso a traducciones automáticas mediante TranslatePress AI, complementos premium, descargas de productos y actualizaciones automáticas. %3$sRenovar ahora %4$s','License key mismatch. The license you entered doesn’t match the <strong>%1$s</strong> version you have installed. <br/>Please check that you’ve installed the correct version for your license from your %2$sTranslatePress account%3$s.'=>'La clave de licencia no coincide. La licencia que ingresaste no coincide con la versión <strong>%1$s</strong> que tienes instalada. <br/>Por favor, verifica que hayas instalado la versión correcta para tu licencia desde tu %2$sTranslatePress Account%3$s.','<br/>If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'<br/>Si tienes solo el plugin gratuito instalado pero agregaste una licencia de pago, por favor instala el plugin de pago desde tu TranslatePress Account.','You have reached the activation limit for your <strong>%1$s</strong> license. <br/>Manage your active sites from %2$s your account %3$s.'=>'Has alcanzado el límite de activación para tu licencia <strong>%1$s</strong>. <br/>Administra tus sitios activos desde %2$s tu cuenta %3$s.','Your license is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Tu licencia está desactivada para esta URL. Reactívala desde <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Administrar sitios.','%1$s automatic translation requires an active license. Please %2$srenew%3$s your license or purchase a new one %4$shere%5$s.'=>'La traducción automática de %1$s requiere una licencia activa. Por favor, %2$srenueva%3$s tu licencia o compra una nueva %4$saquí%5$s.','Please %1$senter%2$s your license key to enable %3$s automatic translation.'=>'Por favor, %1$singresa%2$s tu clave de licencia para habilitar la traducción automática de %3$s.','You have less than 5,000 TranslatePress AI words remaining. To continue automatically translating your website, please %spurchase additional AI words at a discount from your account%s.'=>'Te quedan menos de 5.000 palabras de TranslatePress AI. Para seguir traduciendo automáticamente tu sitio web, por favor %scompra palabras adicionales de TranslatePress AI con descuento desde tu cuenta%s.',' Error: '=>' Error: ','This website is already activated under a free license. Each website can only use one free license. Please upgrade to a premium plan for more TranslatePress AI words from %1$s your account %2$s.'=>'Este sitio web ya está activado con una licencia gratuita. Cada sitio web solo puede usar una licencia gratuita. Por favor, actualiza a un plan premium para obtener más palabras de TranslatePress AI desde %1$s tu cuenta %2$s.','You do not have a valid license for <strong>TranslatePress</strong>. %1$sGet one for free%2$s to get access to TranslatePress AI.'=>'No tienes una licencia válida para <strong>TranslatePress</strong>. %1$sObtén una gratis%2$s para acceder a TranslatePress AI.','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. Upgrade to <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business or Developer</a> to access it + more premium perks!'=>'<strong>NUEVO:</strong> ¡El complemento <strong>Dominio diferente por idioma</strong> ya está aquí! Potencia tu SEO global y crea una experiencia local con dominios específicos de país como .de o .fr. Actualiza a <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business o Developer</a> para acceder a él y más beneficios premium!','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Learn more</a>.'=>'<strong>NUEVO:</strong> ¡El complemento <strong>Dominio diferente por idioma</strong> ya está aquí! Potencia tu SEO global y crea una experiencia local con dominios específicos de país como .de o .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Más información</a>.','The daily quota for machine translation characters exceeded. Please check the <strong>TranslatePress -> <a href="%s">Automatic Translation</a></strong> page for more information.'=>'Se ha excedido la cuota diaria de caracteres de traducción automática.  Consulta la página <strong>TranslatePress -> <a href="%s">Traducción automática</a></strong> para obtener más información.','Marketing optin'=>'Consentimiento de marketing','Opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Acepta nuestras notificaciones de seguridad y actualizaciones de funciones, así como el seguimiento de diagnósticos no sensibles.','TranslatePress Preferred User Language'=>'Idioma de usuario preferido en TranslatePress','Preferred language to navigate the site'=>'Idioma preferido para navegar por el sitio.','The language is automatically set based by the last visited language by the user.'=>'El idioma es establecido automáticamente en base al último idioma visitado por el usuario.','Always use this language'=>'Usar siempre este idioma','By checking this setting the preferred language will remain the one selected above, without the possibility of being changed in the frontend.<br>This language will be used in different operations such as sending email to the user.'=>'Marcando este ajuste el idioma preferido permanecerá seleccionado arriba, sin posibilidad de cambiarlo en la portada.<br>Este idioma será utilizado en diferentes operaciones como enviar un correo electrónico al usuario.','Hello! Seems like you\'ve been using <strong>TranslatePress</strong> for a while now to translate your website. That\'s awesome! '=>'¡Hola! Parece que estuviste usando <strong>TranslatePress</strong> por un tiempo para traducir tu web. ¡Eso es genial! ','If you can spare a few moments to rate it on WordPress.org it would help us a lot (and boost my motivation).'=>'Si pudieras dedicar unos minutos para valorarlo en WordPress.org, eso nos ayudaría bastante (y me motivaría un montón).','~ Razvan, developer of TranslatePress'=>'~ Razvan, desarrollador de TranslatePress','Rate TranslatePress on WordPress.org plugin page'=>'Valora TranslatePress en la página del plugin en WordPress.org','Ok, I will gladly help!'=>'Está bien, ¡con gusto ayudaré!','No, thanks.'=>'No, gracias.','Full Language Names'=>'Nombres de idioma completos','Short Language Names'=>'Nombres de idioma cortos','Flags with Full Language Names'=>'Banderas con nombres de idioma completos','Flags with Short Language Names'=>'Banderas con nombres de idioma cortos','Only Flags'=>'Solo banderas','Full Language Names No HTML'=>'Nombres de idioma completos, sin HTML','Bottom Right'=>'Abajo a la derecha','Bottom Left'=>'Abajo a la izquierda','Top Right'=>'Arriba a la derecha','Top Left'=>'Arriba a la izquierda','Dark'=>'Oscuro','Light'=>'Claro','Deactivate'=>'Desactivar','Activate'=>'Activar','Invalid language code. Please try again.'=>'Código de idioma no válido. Por favor, inténtalo de nuevo.','Language codes can contain only A-Z a-z 0-9 - _ characters. Check your language codes in TranslatePress General Settings.'=>'Los códigos de idioma pueden contener solo los caracteres A-Z a-z 0-9 - _. Revisa tus códigos de idioma en los ajustes generales de TranslatePress.','Error! Duplicate URL slug values.'=>'¡Error! Valores del slug de la URL duplicados.','You cannot select two languages that have the same <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">iso code</a> but different formalities because doing so will lead to duplicate <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang tags</a>.'=>'No puedes seleccionar dos idiomas que tengan el mismo <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">código ISO</a> pero formalidades diferentes, porque si lo haces se duplicarán las <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">etiquetas hreflang</a>.','Duplicate language detected.<br>Each language can only be added once to ensure accurate translation management.<br> Please change the duplicate language entry and try again. '=>'Se ha detectado un idioma duplicado.<br>Cada idioma sólo puede agregarse una vez para garantizar una gestión precisa de la traducción.<br> Por favor, cambia la entrada del idioma duplicado e inténtalo de nuevo. ','Current Language'=>'Idioma actual','Opposite Language'=>'Idioma opuesto','General'=>'General','Translate Site'=>'Traducir el sitio','Addons'=>'Extensiones','License'=>'Licencia','Settings'=>'Ajustes','Activate License'=>'Activar licencia','Pro Features'=>'Funcionalidades PRO','Need Help?'=>'¿Necesitas ayuda?','Recent community discussions'=>'Discusiones recientes de la comunidad','Loading...'=>'Cargando...','Unable to load forum posts'=>'No se pueden cargar las entradas del foro','Ask a Question'=>'Haz una pregunta','View All Topics'=>'Ver todos los temas','by'=>'por','Have a question?'=>'¿Tienes una pregunta?','Get help directly from the plugin developers, suggest improvements, or share your feedback!'=>'¡Obtén ayuda directamente de los desarrolladores del plugin, sugiere mejoras o comparte tus comentarios!','Tip for faster help:'=>'Consejo para obtener ayuda más rápido:','Include what you tried, what you expected, and what happened. Screenshots help!'=>'Incluye lo que intentaste, lo que esperabas y lo que sucedió. ¡Las capturas de pantalla ayudan!','Toggle support chat'=>'Alternar chat de soporte','Ask the community'=>'Pregunta a la comunidad','Close'=>'Cerrar','Empty feed response'=>'Respuesta de feed vacía','Unable to parse feed'=>'No se pudo analizar el feed','Just now'=>'Justo ahora','%d hour ago'=>'hace %d hora' . "\0" . 'hace %d horas','%d day ago'=>'hace %d día' . "\0" . 'hace %d días','Source'=>'Origen','Srcset'=>'Srcset','Alt attribute'=>'Atributo Alt','Title attribute'=>'Atributo título','Anchor link'=>'Enlace ancla','Placeholder attribute'=>'Atributo de marcador de posición','Submit attribute'=>'Enviar atributo','Text'=>'Texto','Video Poster'=>'Poster del video','plural form'=>'forma plural','one'=>'uno','few'=>'pocos','many'=>'muchos','other'=>'otro','Saved'=>'Guardado','Save'=>'Guardar','Saving translation...'=>'Guardando traducción...','You have unsaved changes!'=>'¡Tienes cambios sin guardar!','Discard changes'=>'Descartar cambios','Discard All'=>'Descartar todo','Loading Strings...'=>'Cargando cadenas...','Select string to translate...'=>'Elige la cadena a traducir...','Close Editor'=>'Cerrar editor','From'=>'Del','To'=>'Al','Add Media'=>'Agregar medios','Other languages'=>'Otros idiomas','Context'=>'Contexto','View Website As'=>'Ver web como','Available in our Pro Versions'=>'Disponible en nuestras versiones Pro','Select or Upload Media'=>'Elige o sube medios','Use this media'=>'Usar este medio','Translate'=>'Traducir','Translate entire block element'=>'Traducir el bloque completo','Split block to translate strings individually'=>'Segmentar el bloque para traducir las cadenas individualmente','Save changes to translation. Shortcut: CTRL(⌘) + S'=>'Guarda los cambios en la traducción. Atajo: CTRL(⌘) + S','Navigate to next string in dropdown list. Shortcut: CTRL(⌘) + ALT + Right Arrow'=>'Navega a la cadena siguiente de la lista desplegable. Atajo: CTRL(⌘) + ALT + Flecha derecha','Navigate to previous string in dropdown list. Shortcut: CTRL(⌘) + ALT + Left Arrow'=>'Navega a la cadena anterior de la lista desplegable. Atajo: CTRL(⌘) + ALT + Flecha izquierda','Discard all changes. Shortcut: CTRL(⌘) + ALT + Z'=>'Descarta todos los cambios. Atajo: CTRL(⌘) + ALT + Z','Discard changes to this text box. To discard changes to all text boxes use shortcut: CTRL(⌘) + ALT + Z'=>'Descarta los cambios de esta caja de texto. Para descartar los cambios en todas las cajas de texto, usa el atajo: CTRL(⌘) + ALT + Z','Dismiss tooltip'=>'Descartar este mensaje','Quick Intro'=>'Introducción rápida','Are you sure you want to split this phrase into smaller parts?'=>'¿Seguro que quieres segmentar esta frase en partes más pequeñas?','This string is not ready for translation yet. <br>Try again in a moment...'=>'Esta cadena todavía no está lista para su traducción.<br>Inténtalo de nuevo en un momento...','For this option to work, please update the Browse as other role add-on to the latest version.'=>'Para que funcione esta opción, actualiza el navegador y las otras extensiones de perfil a la última versión.','To translate slugs, please update the SEO Pack add-on to the latest version.'=>'Para traducir slugs, actualiza la extensión SEO Pack a la última versión.','You can add a new language from <a href="%s">Settings->TranslatePress</a>'=>'Puedes agregar un nuevo idioma en <a href="%s">Ajustes -> TranslatePress</a>.','However, you can still use TranslatePress to <strong style="background: #f5fb9d;">modify gettext strings</strong> available in your page.'=>'De todas maneras, puedes seguir utilizando TranslatePress para <strong style="background: #f5fb9d;">modificar las cadenas de Gettext</strong> disponibles en tu página.','Strings that are user-created cannot be modified, only those from themes and plugins.'=>'Las cadenas creadas por los usuarios no pueden ser modificadas, solo las de los temas y plugins.','Extra Translation Features'=>'Funcionalidades adicionales de traducción','Support for 130+ Extra Languages'=>'Compatibilidad con más de 130 idiomas adicionales','Access to TranslatePress AI'=>'Acceso a TranslatePress AI','Translate SEO Title, Description, Slug'=>'Traducción del título, la descripción y el slug para SEO','Publish only when translation is complete'=>'Publicación solo cuando la traducción esté completa','Translate by Browsing as User Role'=>'Traducción navegando con un perfil de usuario','Different Menu Items for each Language'=>'Elementos de menú diferentes según el idioma','Automatic User Language Detection'=>'Detección automática del idioma del usuario','Upgrade to PRO'=>'Actualizar a PRO','Upgrade to PRO with our biggest discount of the year!'=>'¡Mejora a PRO con nuestro mayor descuento del año!','This Black Friday, get access to these features and more at a fraction of the costs:'=>'Este Black Friday, accede a estas funciones y a muchas más por una fracción de su costo:','No available suggestions'=>'No hay sugerencias disponibles.','Suggestions from translation memory'=>'Sugerencias de la memoria de traducción','Click to Copy'=>'Haz clic para copiar','Human Translation'=>'Traducción humana','Machine Translation'=>'Traducción automática','Text on this page is %s% translated into all languages.'=>'El texto de esta página está traducido al %s% a todos los idiomas.','%1$s% of text on this page is translated into %2$s.'=>'El %1$s% del texto de esta página está traducido al %2$s.','This page is %1$s% translated into %2$s.'=>'Esta página está traducida mediante %1$s% a %2$s.','The slug that you are trying to edit is present in other slug types:%s%. Editing it will replace each occurrence, regardless of the current type.'=>'El slug que intentas editar está presente en otros tipos de slug:%s. Editarlo reemplazará cada ocurrencia, independientemente del tipo actual.','Hover any text on the page, click %s,<br> then modify the translation in the sidebar.'=>'Pasa el cursor sobre cualquier texto de la página, haz clic en %s,<br> luego modifica la traducción en la barra lateral.','Don\'t forget to Save Translation. Use keyboard shortcut CTRL(⌘) + S'=>'No olvides guardar la traducción. Usa el atajo de teclado CTRL(⌘) + S','Switch language to see the translation changes directly on the page.'=>'Cambia de idioma para ver los cambios directamente en la página.','Search for any text in this page in the dropdown.'=>'Busca cualquier texto en esta página en la lista desplegable.','Your %s license has <span class="trp-license-status-emphasized">expired</span>.'=>'Tu licencia de %s ha <span class="trp-license-status-emphasized">caducado</span>.','Please renew your license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'Renueva tu licencia para continuar recibiendo acceso a TranslatePress AI, complementos premium, actualizaciones automáticas y soporte.','Renew Now'=>'Renovar ahora','<strong>This Black Friday, renew your license at a special price</strong> to continue receiving access to product downloads, automatic updates, and support.'=>'<strong>Este Black Friday, renueva tu licencia a un precio especial</strong> para seguir recibiendo acceso a descargas de productos, actualizaciones automáticas y asistencia.','Get Deal'=>'Consigue la oferta','Your %s license was <span class="trp-license-status-emphasized">refunded</span>.'=>'Tu licencia de %s ha sido <span class="trp-license-status-emphasized">reembolsada</span>.','Please purchase a new license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'Compra una nueva licencia para continuar recibiendo acceso a TranslatePress AI, complementos premium, actualizaciones automáticas y soporte.','Purchase a new license'=>'Compra una nueva licencia','Your %s license is <span class="trp-license-status-emphasized">missing or invalid</span>.'=>'Tu licencia de %s está <span class="trp-license-status-emphasized">perdida o no es válida</span>.','Please enter a valid license to get access to TranslatePress AI, premium addons, automatic updates and support. Need a license key? %1$sPurchase one now%2$s'=>'Ingresa una licencia válida para obtener acceso a TranslatePress AI, complementos premium, actualizaciones automáticas y soporte. ¿Necesitas una clave de licencia? %1$sCompra una ahora%2$s','Enter a valid license'=>'Introduce una licencia válida','Slugs'=>'Slugs','Meta Information'=>'Información meta','String List'=>'Lista de cadenas','Gettext Strings'=>'Cadenas de getttext','Images'=>'Imágenes','Videos'=>'Videos','Audios'=>'Audios','Dynamically Added Strings'=>'Cadenas agregadas dinámicamente','Translation Editor'=>'Editor de traducción','Edit translations by visually selecting them on each site page'=>'Edita las traducciones seleccionándolas visualmente en cada página del sitio','String Translation'=>'Traducción de la cadena','Edit url slug translations, plugins and theme translation (emails, forms etc.)'=>'Edita traducciones de slug de url, plugins y traducción de temas (correos electrónicos, formularios, etc.)','Current User'=>'Usuario actual','Logged Out'=>'Desconectado','Translate Page'=>'Traduce la página','Add a New Language'=>'Agregar un nuevo idioma','Get a Free AI License'=>'Obtener una licencia AI gratuita','Your License is Invalid'=>'Tu licencia no es válida','Get More AI Words (%d left)'=>'Obtener más palabras de AI (%d restantes)','Opens post in the translation editor. Post must be saved as draft or published beforehand.'=>'Abre las entradas en el editor de traducciones. La entrada debe primero guardarse como borrador o publicarse.','Security check'=>'Revisión de seguridad','<strong>Warning:</strong> Some strings have possibly incorrectly encoded characters. This may result in breaking the queries, rendering the page untranslated in live mode. Consider revising the following strings or their method of outputting.'=>'<strong>Advertencia:</strong> Algunas cadenas contienen caracteres que podrían estar codificados incorrectamente, lo que puede resultar en consultas dañadas y ocasionar que la página se muestre en directo como no traducida. Considera revisar las siguientes cadenas o su método de salida.','TranslatePress data update'=>'Actualización de datos de TranslatePress','We need to update your translations database to the latest version.'=>'Necesitamos actualizar la base de datos de tus traducciones a la última versión.','Updating will allow editing translations of localized text from plugins and theme. Existing translation will still work as expected.'=>'La actualización permitirá editar las traducciones del texto localizado de los plugins y del tema. Las traducciones existentes seguirán funcionando como es debido.','IMPORTANT: It is strongly recommended to first backup the database!
Are you sure you want to continue?'=>'IMPORTANTE: Se recomienda encarecidamente hacer primero una copia de seguridad de la base de datos
¿Seguro que quieres continuar?','Run the updater'=>'Ejecutar el actualizador','Updating will allow editing translations of slugs. Existing translation will still work as expected.'=>'La actualización permitirá editar las traducciones de los slugs. Las traducciones existentes seguirán funcionando como es debido.','Please activate the SEO Addon from <br/>WordPress -> Settings -> TranslatePress -> Addons section'=>'Activa el complemento SEO desde <br/>WordPress -> Ajustes -> TranslatePress -> sección de Complementos','Go to Addons'=>'Ir a Extensiones','The SEO Pack add-on allows translation of all the URL slugs:'=>'La extensión SEO Pack permite traducir todos los slugs de URL:','Taxonomy slugs'=>'Slugs de taxonomía','Term slugs'=>'Slugs de términos','Post slugs (this includes pages and custom post types)'=>'Slugs de publicaciones (esto incluye entradas, páginas y tipos de contenido personalizados)','Post type base slugs'=>'Slugs base de tipos de contenido','WooCommerce slugs'=>'Slugs de WooCommerce','The SEO Pack add-on is available with ALL premium versions of the plugin.'=>'La extensión Pack SEO está disponible con TODAS las versiones premium del plugin.','Upgrade to Pro'=>'Actualiza a la versión Pro','Description'=>'Descripción','Article Section'=>'Sección de artículo','Article Tag'=>'Etiqueta de artículo','OG Title'=>'Título para OpenGraph','OG Site Name'=>'Nombre del sitio para OpenGraph','OG Description'=>'Descripción para OpenGraph','OG Image Alt'=>'Alt de la imagen para OpenGraph','Twitter Title'=>'Título para Twitter','Twitter Description'=>'Descripción para Twitter','Twitter Image Alt'=>'Alt de la imagen para Twitter','Page Title'=>'Título de la página','Dublin Core Title'=>'Título para Dublin Core','Dublin Core Description'=>'Descripción para Dublin Core','OG Image'=>'Imagen para OpenGraph','OG Image Secure URL'=>'URL segura de la imagen para OpenGraph','Twitter Image'=>'Imagen para Twitter','Removing cdata dictionary strings for language %s...'=>'Eliminando cadenas cdata del diccionario del idioma %s…','Removing untranslated dictionary links for language %s...'=>'Eliminando enlaces de diccionario sin traducir del idioma %s…','Removing duplicated gettext strings for language %s...'=>'Eliminando cadenas duplicadas de Gettext para el idioma %s...','Removing duplicated dictionary strings for language %s...'=>'Eliminando cadenas de diccionario duplicadas para el idioma %s...','Removing untranslated dictionary strings where translation is available for language %s...'=>'Eliminando cadenas de diccionario no traducidas en las que hay una traducción disponible para el idioma %s...','Inserting original strings for language %s...'=>'Insertando cadenas originales para el idioma %s...','Cleaning original strings table for language %s...'=>'Limpiando la tabla de cadenas originales para el idioma %s...','Updating original string ids for language %s...'=>'Actualizando los ID de las cadenas originales para el idioma %s...','Regenerating original meta table for language %s...'=>'Regenerando la tabla meta original para el idioma %s...','Cleaning original meta table for language %s...'=>'Limpiando la tabla meta original para el idioma %s...','Replacing original id NULL with value for language %s...'=>'Sustituyendo el id original NULL por el valor del idioma %s...','Inserting gettext original strings for language %s...'=>'Insertando cadenas originales gettext para el idioma %s...','Cleaning gettext original strings table for language %s...'=>'Limpiando la tabla de cadenas originales gettext para el idioma %s...','Updating gettext original string ids for language %s...'=>'Actualizando los ID de las cadenas originales de gettext para el idioma %s...','Migrating taxonomy and post type base slugs to new table structure...'=>'Migrando los slugs base de taxonomía y tipos de contenido a la nueva estructura de tabla...','Migrating post slugs to new table structure for language %s...'=>'Migrando los slugs de publicaciones a la nueva estructura de tabla para el idioma %s...','Migrating term slugs to new table structure for language %s...'=>'Migrando los términos a la nueva estructura de tabla para el idioma %s...','Finishing up...'=>'Terminando…','Database optimization did not complete successfully. We recommend restoring the original database or <a href="%s" >trying again.</a>'=>'La optimización de la base de datos no se completó correctamente. Recomendamos restaura la base de datos original o <a href="%s" >intentarlo de nuevo.</a>','Update aborted! Your user account doesn\'t have the capability to perform database updates.'=>'¡Actualización interrumpida! Tu cuenta de usuario no tiene la capacidad de ejecutar actualizaciones de la base de datos.','Update aborted! Invalid nonce.'=>'¡Actualización interrumpida! Nonce no válido.','Update aborted! Incorrect action.'=>'¡Actualización interrumpida! Acción incorrecta.','Update aborted! Incorrect language code.'=>'¡Actualización interrumpida! Código de idioma incorrecto.','Updating database to version %s+'=>'Actualizando la base de datos a la versión %s+','Processing table for language %s...'=>'Procesando la tabla para el idioma %s...','Back to TranslatePress Settings'=>'Volver a los ajustes de TranslatePress','Successfully updated database!'=>'¡La base de datos se ha actualizado correctamente!',' done.'=>' hecho.','All individual TranslatePress add-on plugins <a href="%1$s" target="_blank">have been discontinued</a> and are now included in the premium Personal, Business and Developer versions of TranslatePress. Please log into your <a href="%2$s" target="_blank">account page</a>, download the new premium version and install it. Your individual addons settings will be ported over.'=>'Todos los plugins de extensión individuales de TranslatePress <a href="%1$s" target="_blank">se han descontinuado</a> y están incluidos ahora en las versiones de pago Personal, Business y Developer de TranslatePress. Ingresa a la <a href="%2$s" target="_blank">página de tu cuenta</a>, descarga la nueva versión de pago e instálala. Se importarán los ajustes de tus extensiones individuales.','Brand-new Language Switcher Settings are here!'=>'¡Ya están aquí los nuevos Ajustes del conmutador de idioma!','Explore pre-made templates, switch colors, flag styles, spacing, layouts & more. Use the live preview to perfect your switcher in seconds.'=>'Explora plantillas prediseñadas, cambia colores, estilos de bandera, espaciado, diseños y mucho más. Utiliza la vista previa en vivo para perfeccionar tu conmutador en segundos.','Start customizing'=>'Comienza a personalizar','Read documentation'=>'Leer la documentación','TranslatePress'=>'TranslatePress','<strong>TranslatePress</strong> requires <strong><a href="http://php.net/manual/en/book.mbstring.php">Multibyte String PHP library</a></strong>. Please contact your server administrator to install it on your server.'=>'<strong>TranslatePress</strong> necesita <strong><a href="http://php.net/manual/en/book.mbstring.php">la biblioteca PHP Multibyte String</a></strong>. Contacta con tu administrador para que la instale en el servidor.','Detected long query limitation on WPEngine hosting. Some large pages may appear untranslated. You can remove limitation by adding the following to your site’s wp-config.php: define( \'WPE_GOVERNOR\', false ); '=>'Se ha detectado un límite de consulta larga en el proveedor de alojamiento WPEngine. Algunas páginas grandes podrían aparecer sin traducir. Puedes quitar el límite agregando lo siguiente en el wp-config.php de tu sitio: define( \'WPE_GOVERNOR\', false ); ','Custom Language Flag'=>'Bandera de idioma personalizado','The Language code of the added custom language cannot be empty.'=>'El código de idioma del idioma personalizado agregado no puede estar en blanco.','The Language code of the added custom language is invalid.'=>'El código de idioma del idioma personalizado agregado no es válido.','The Automatic Translation Code of the added custom language is invalid.'=>'El código de traducción automática del idioma personalizado agregado no es válido.','TranslatePress Add-ons'=>'Extensiones de TranslatePress','You must first purchase this version to have access to the addon %1$shere%2$s'=>'Debes comprar primero esta versión para tener acceso a la extensión %1$saquí%2$s.','Please %1$senter your license%2$s key first, to activate this addon.'=>'Por favor, %1$singresa tu clave de licencia%2$s primero para activar este complemento.','You need an active license to have access to the addon. Renew or purchase a new one %1$shere%2$s.'=>'Necesitas una licencia activa para acceder al complemento. Renueva o compra una nueva %1$saquí%2$s.','Advanced Add-ons'=>'Complementos avanzados','These addons extend your translation plugin and are available in the Developer, Business and Personal plans.'=>'Estas extensiones mejoran tu plugin de traducciones y están disponibles en los planes Developer, Business y Personal.','SEO Pack'=>'SEO Pack','SEO Pack (Legacy)'=>'SEO Pack (Heredado)','SEO support for page slug, page title, description and facebook and twitter social graph information. The HTML lang attribute is properly set.'=>'Compatibilidad SEO para el slug y el título de la página, la descripción y la información para los grafos sociales de Facebook y Twitter. Establece correctamente el atributo HTML “lang”.','Multiple Languages'=>'Múltiples idiomas','Add as many languages as you need for your project to go global. Publish your language only when all your translations are done.'=>'Agrega tantos idiomas como necesites para hacer global tu proyecto. Publica en tu idioma solo cuando estén listas todas tus traducciones.','Pro Add-ons'=>'Extensiones Pro','These addons extend your translation plugin and are available in the Business and Developer plans.'=>'Estas extensiones mejoran tu plugin de traducciones y están disponibles en los planes Business y Developer.','DeepL Automatic Translation'=>'Traducción automática de DeepL','Automatically translate your website through the DeepL API.'=>'Traduce automáticamente tu web mediante la API de DeepL.','Prompts visitors to switch to their preferred language based on their browser settings or IP address and remembers the last visited language.'=>'Pide a los visitantes que cambien a su idioma preferido en función de la configuración de su navegador o de su dirección IP y recuerda el último idioma visitado.','Translator Accounts'=>'Cuentas de traductor','Create translator accounts for new users or allow existing users that are not administrators to translate your website.'=>'Crea cuentas de traductor para nuevos usuarios o permite a los usuarios existentes que no sean administradores que traduzcan tu web.','Browse As User Role'=>'Navegar como perfil de usuario','Navigate your website just like a particular user role would. Really useful for dynamic content or hidden content that appears for particular users.'=>'Navega por tu web como lo haría un perfil de usuario concreto. Muy útil para contenidos dinámicos u ocultos que aparecen para usuarios concretos.','Navigation Based on Language'=>'Navegación según el idioma','Configure different menu items for different languages.'=>'Configura diferentes elementos de menú según los diferentes idiomas.','Different Domain per Language'=>'Dominio diferente por idioma','Connect separate domains or subdomains to each of your translated versions. Strengthen your brand’s local identity and boost SEO performance for every language you support.'=>'Conecta dominios separados o subdominios a cada una de tus versiones traducidas. Fortalece la identidad local de tu marca y mejora el rendimiento de SEO para cada idioma que admites.','Recommended Plugins'=>'Plugins recomendados','A short list of plugins you can use to extend your website.'=>'Una pequeña lista de plugins que puedes usar para mejorar tu web.','Profile Builder'=>'Maquetador de perfiles','Capture more user information on the registration form with the help of Profile Builder\'s custom user profile fields and/or add an Email Confirmation process to verify your customers accounts.'=>'Obtén más información del usuario en el formulario de registro con la ayuda de los campos personalizados de perfiles de usuario del maquetador de perfiles, y agrega un procedimiento de confirmación de correo electrónico para verificar las cuentas de tus clientes.','Paid Member Subscriptions'=>'Suscripciones de pago para miembros','Accept user payments, create subscription plans and restrict content on your membership site.'=>'Acepta pagos de usuarios, crea planes de suscripción y restringe contenido en tu sitio de membresía.','WP Webhooks Automator'=>'WP Webhooks Automator','Create no-code automations and workflows on your WordPress site. Easily connect your plugins, sites and apps together.'=>'Crea automatizaciones y flujos de trabajo sin código en tu sitio WordPress. Conecta fácilmente tus plugins, sitios y aplicaciones.','Save Changes'=>'Guardar cambios','TranslatePress Errors'=>'Errores de TranslatePress','There are no logged errors.'=>'No hay errores registrados.','Change language'=>'Cambiar idioma','Website language selector'=>'Selector de idioma del sitio web','WordPress Translation Plugin'=>'Plugin de traducción para WordPress','Available languages'=>'Idiomas disponibles','Language Switcher update notice'=>'Aviso de actualización del conmutador de idiomas','Legacy language switcher is currently enabled'=>'El cambiador de idioma heredado está activado','We’ve upgraded the switcher for richer customization and a better user experience.<br>In order to use the new configurator, turn off <strong>Load legacy language switcher</strong>.'=>'Hemos actualizado el selector para una mayor personalización y una mejor experiencia de usuario.<br>Para usar el nuevo configurador, desactiva <strong>Cargar selector de idioma heredado</strong>.','Note: You can switch back anytime from <strong>Advanced Settings → <a href="%s">Troubleshooting</a></strong>.'=>'Nota: Puedes volver a cambiarlo en cualquier momento desde <strong>Ajustes avanzados → <a href="%s">Solución de problemas</a></strong>.','Enable the new switcher'=>'Activar el nuevo conmutador','Your License Key is valid.'=>'Tu clave de licencia es válida.','Your License Key is invalid.'=>'Tu clave de licencia no es válida.','Your License has expired.'=>'Tu licencia ha caducado.','Deactivate License'=>'Desactivar licencia','Add a license key'=>'Agrega una clave de licencia','License Key'=>'Clave de licencia','Manage your license in your %1$s.'=>'Gestiona tu licencia en tu %1$s.','Account Page'=>'Página de cuenta','Don’t have a TranslatePress AI License Key?'=>'¿No tienes una clave de licencia de TranslatePress AI?','You can get one for %1$sfree%2$s, by creating a free account. It includes:'=>'Puedes obtener uno %1$sgratis%2$s al crear una cuenta gratuita. Incluye:','Access to TranslatePress AI for instant automatic translations'=>'Acceso a TranslatePress AI para traducciones automáticas instantáneas','2000 AI words to translate automatically'=>'2000 palabras de IA para traducir automáticamente','Get a free License Today'=>'Obtén hoy una licencia gratuita','Debug Information'=>'Información de depuración','Debug Data for License Checking'=>'Datos de depuración para la verificación de licencia','Debug Data for License Activation'=>'Datos de depuración para la activación de licencia','Get more AI words and unlock all features with TranslatePress Pro.'=>'Obtén más palabras de IA y desbloquea todas las funciones con TranslatePress Pro.','Upgrade now ↗'=>'Mejora ahora ↗','Already purchased a Premium version?'=>'¿Ya has comprado una versión Premium?','Go to your %1$s'=>'Ve a tu %1$s','TranslatePress.com Account'=>'Cuenta de TranslatePress.com','Download & Install the Pro plugin'=>'Descarga e instala el plugin Pro','Learn More'=>'Más información','Get a translation volume estimate with a detailed breakdown per page'=>'Obtén una estimación del volumen de traducción con un desglose detallado por página','Find how many translatable words are on your website'=>'Encuentra cuántas palabras traducibles hay en tu sitio web','Enable Automatic Translation'=>'Activar traducción automática','To use <strong>DeepL</strong> for automatic translation, activate this Pro add-on from the <a href="%1$s" target="_self" title="%2$s">%2$s</a>.'=>'Para utilizar la traducción automática de <strong>DeepL</strong>, activa esta extensión Pro desde la <a href="%1$s" target="_self" title="%2$s">%2$s</a>.','<strong>DeepL</strong> automatic translation is available as a <a href="%1$s" target="_blank" title="%2$s">%2$s</a>.'=>'La traducción automática de <strong>DeepL</strong> está disponible como <a href="%1$s" target="_blank" title="%2$s">%2$s</a>.','By upgrading you\'ll get access to all paid add-ons, premium support and help fund the future development of TranslatePress.'=>'Al actualizar, obtendrás acceso a todas las extensiones de pago y al soporte Premium, y ayudarás a financiar el desarrollo futuro de TranslatePress.','Please note that DeepL API usage is paid separately. See <a href="https://www.deepl.com/pro.html#developer">DeepL pricing information</a>.'=>'Ten en cuenta que el uso de la API de DeepL se paga por separado. Consulta la <a href="https://www.deepl.com/pro.html#developer">información sobre precios de DeepL</a>.','TranslatePress Pro Add-ons'=>'Extensiones Pro de TranslatePress','Test API credentials'=>'Probar las credenciales de la API','Check if the selected translation engine is configured correctly.'=>'Comprueba si el motor de traducción seleccionado está configurado correctamente.','Alternative Engines'=>'Motores alternativos','Switch to TranslatePress AI'=>'Cambiar a TranslatePress AI','Integrate machine translation directly with your WordPress website.'=>'Integra la traducción automática directamente en tu sitio WordPress.','More info'=>'Más información','Choose which engine you want to use in order to %1$s automatically translate your website.'=>'Elige qué motor quieres usar para %1$straducir automáticamente tu sitio web.','Automatic Translation Settings'=>'Configuración de traducción automática','AI Words Low Notification'=>'Notificación de pocas palabras de IA','Receive an email notification when your TranslatePress AI word count drops below the specified threshold.'=>'Recibe una notificación por correo electrónico cuando el recuento de palabras de TranslatePress AI descienda por debajo del umbral especificado.','This feature is only available when using the TranslatePress AI translation engine.'=>'Esta función solo está disponible al usar el motor de traducción TranslatePress AI.','Notification Email'=>'Correo electrónico de notificación','The email address where the low AI words notification will be sent.'=>'La dirección de correo electrónico donde se enviará la notificación de pocas palabras de IA.','Word Threshold'=>'Umbral de palabras','words'=>'palabras','You will be notified when remaining AI words drop below this number.'=>'Se te notificará cuando las palabras de IA restantes desciendan por debajo de este número.','Automatically Translate Slugs'=>'Traducir los slugs automáticamente','Generate automatic translations of slugs for posts, pages and Custom Post Types.<br/>The slugs will be automatically translated starting with the second refresh of each page.'=>'Genera traducciones automáticas de los slugs para entradas, páginas y tipos de contenido personalizado.<br/>Los slugs se traducirán automáticamente a partir de la segunda actualización de cada página.','This feature is only available in the paid version. Upgrade TranslatePress and unlock more premium features.'=>'Esta función solo está disponible en la versión de pago. Actualiza TranslatePress y desbloquea más funciones premium.','Requires <a href="%s" title="TranslatePress Add-on SEO Pack documentation" target="_blank">SEO Pack Add-on</a> to be installed and activated.'=>'Requiere que el <a href="%s" title="TranslatePress Add-on SEO Pack documentation" target="_blank">complemento SEO Pack</a> esté instalado y activado.','Upgrade now'=>'Actualizar ahora','Block Crawlers'=>'Bloquear rastreadores','Block crawlers from triggering automatic translations on your website.<br>This will not prevent crawlers from accessing this site\'s pages.'=>'Bloquea los rastreadores para que no activen las traducciones automáticas en tu web.<br>Esto no impedirá que los rastreadores accedan a las páginas de este sitio.','Limit machine translation / characters per day'=>'Limitar traducción automática por caracteres diarios','Add a limit to the number of automatically translated characters so you can better budget your project.'=>'Agrega un límite a la cantidad de caracteres traducidos automáticamente para que puedas presupuestar mejor tu proyecto.','characters per day'=>'caracteres por día','Today\'s Character Count: '=>'Conteo de caracteres de hoy: ','Log machine translation queries.'=>'Registrar consultas de traducción automática','Only enable for testing purposes. Can impact performance.<br>All records are stored in the wp_trp_machine_translation_log database table. Use a plugin like <a href="https://wordpress.org/plugins/wp-data-access/" target="_blank">WP Data Access</a> to browse the logs or directly from your database manager (PHPMyAdmin, etc.)'=>'Actívalo solo para propósitos de prueba. Puede influir en el rendimiento.<br>Todos los registros se almacenan en la tabla wp_trp_machine_translation_log de la base de datos. Usa un plugin como <a href="https://cl.wordpress.org/plugins/wp-data-access/" target="_blank">WP Data Access</a> para explorar los registros, o accede directamente desde tu gestor de bases de datos (PHPMyAdmin, etc.).','Test API Credentials'=>'Probar credenciales de API','HTTP Referrer: '=>'Referente HTTP: ','Use this HTTP Referrer if the API lets you restrict key usage from its Dashboard.'=>'Usa esta referencia HTTP si la API te permite restringir el uso de la clave desde su escritorio.','Response'=>'Respuesta','Response Body'=>'Cuerpo de la respuesta','Entire Response From wp_remote_get():'=>'Respuesta completa de wp_remote_get():','All Languages'=>'Todos los idiomas','Select the languages you wish to make your website available in.'=>'Elige los idiomas que quieres tener disponibles en tu web.','Formality'=>'Formalidad','Code'=>'Código','Slug'=>'Slug','Default'=>'Por defecto','Formal'=>'Formal','Informal'=>'Informal','Language'=>'Idioma','This language does not support formality. '=>'Este idioma no admite formalidad. ','Are you sure you want to remove this language?'=>'¿Estás seguro de que quieres quitar este idioma?','Custom Languages'=>'Idiomas personalizados','To Add more languages activate the Multiple Languages Addon'=>'Para agregar más idiomas, activa el complemento de múltiples idiomas','You need an active license to add more languages. Verify in your %1$saccount%2$s that your license is valid'=>'Necesitas una licencia activa para agregar más idiomas. Verifica en tu %1$scuenta%2$s que tu licencia sea válida','Please %1$senter your license%2$s key first to add more languages.'=>'Por favor, %1$singresa tu clave de licencia%2$s primero para agregar más idiomas.','Adding more than two languages is a paid feature. Upgrade TranslatePress and unlock more premium features.'=>'Agregar más de dos idiomas es una función de pago. Actualiza TranslatePress y desbloquea más funciones premium.','Website Languages'=>'Idiomas del sitio web','Default Language'=>'Idioma por defecto','Select the language your content is written in.'=>'Selecciona el idioma en el que está escrito tu contenido.','WARNING. Changing the default language will invalidate existing translations.'=>'ADVERTENCIA: Al cambiar el idioma por defecto, las traducciones existentes dejarán de ser válidas.','Even changing from en_US to en_GB, because they are treated as two different languages.'=>'Incluso si cambias es_ES por es_MX, porque se tratan como dos idiomas distintos.','In most cases changing the default flag is all it is needed: '=>'En la mayoría de los casos, basta con cambiar la bandera por defecto: ','replace the default flag'=>'reemplazar la bandera por defecto.','Re-run Setup Wizard'=>'Volver a ejecutar el asistente de configuración','The Setup wizard allows you to quickly setup TranslatePress. You can initiate it at any time.'=>'El asistente de configuración te permite configurar TranslatePress rápidamente. Puedes iniciarlo en cualquier momento.','Language Settings'=>'Ajustes de idioma','Use Native language name'=>'Usar nombre de idioma nativo','Check if you want to display languages in their native names. Otherwise, languages will be displayed in English.'=>'Marca esta opción si quieres mostrar los idiomas en sus nombres nativos. De lo contrario, los idiomas se mostrarán en inglés.','Use a subdirectory for the default language'=>'Usar un subdirectorio para el idioma por defecto','Check if you want to add the subdirectory in the URL for the default language.</br>By checking this option, the default language seen by website visitors will become the first one in the "All Languages" list.'=>'Marca esta opción si quieres agregar el subdirectorio en la URL para el idioma predeterminado.</br>Al marcar esta opción, el idioma predeterminado que ven los visitantes del sitio será el primero de la lista "Todos los idiomas".','Force language in custom links'=>'Forzar idioma en enlaces personalizados','Select Yes if you want to force custom links without language encoding to keep the currently selected language.'=>'Elige “Sí” si quieres forzar que los enlaces personalizados sin codificación de idioma mantengan el idioma elegido actual.','Shortcode '=>'Shortcode ','Use shortcode on any page or widget.'=>'Utiliza el shortcode en cualquier página o widget.','You can also add the <a href="%s" title="Language Switcher Block Documentation">Language Switcher Block</a> in the WP Gutenberg Editor.'=>'También puedes agregar el <a href="%s" title="Documentación del bloque de cambio de idioma">Bloque de cambio de idioma</a> en el editor Gutenberg de WP.','Menu item'=>'Elemento de menú','Go to  %1$s Appearance -> Menus%2$s to add languages to the Language Switcher in any menu.'=>'Ve a %1$sApariencia -> Menús%2$s para agregar idiomas al conmutador de idiomas de cualquier menú.','Learn more in our documentation.'=>'Aprende más en nuestra documentación.','Floating language selection'=>'Conmutador flotante de idioma','Add a floating dropdown that follows the user on every page.'=>'Agrega una lista desplegable flotante que sigue al usuario en todas las páginas.','Show "Powered by TranslatePress"'=>'Mostrar “Funciona con TranslatePress”','Show the small "Powered by TranslatePress" label in the floater language switcher.'=>'Muestra la etiqueta pequeña “Funciona con TranslatePress” en el conmutador flotante de idioma.','5 Days to Better Multilingual Websites'=>'Consigue mejores webs multilingües en 5 días','%sJoin our FREE & EXCLUSIVE onboarding course%s and learn how to grow your multilingual traffic, reach international markets, and save time & money while getting the most out of TranslatePress!'=>'%sÚnete a nuestro curso de inducción GRATUITO y EXCLUSIVO%s, ¡y aprende cómo hacer crecer tu tráfico multilingüe, alcanzar los mercados internacionales y ahorrar tiempo y dinero a la vez que sacas el máximo provecho de TranslatePress!','Invalid email address'=>'Dirección de correo electrónico no valida','Your email'=>'Tu correo electrónico','Sign me up!'=>'¡Quiero registrarme!','Sign up with your email address and receive a 5-part email guide to help you maximize the power of TranslatePress.'=>'Regístrate con tu dirección de correo electrónico y recibe por este medio una guía de 5 partes para ayudarte a sacar el máximo provecho de TranslationPress.','Dismiss email course notification'=>'Descartar aviso del curso por correo electrónico','Hey %s,<br>Never miss an important update - opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Hola %s,<br>No pierdas nunca una actualización importante: acepta nuestros avisos de actualizaciones de seguridad y características, y el seguimiento no confidencial de diagnóstico.','Allow & Continue'=>'Permitir y continuar','Skip'=>'Saltar','This will allow TranslatePress to:'=>'Esto permitirá a TranslatePress:','Your profile overview'=>'Resumen de tu perfil','Name and email address'=>'Nombre y dirección de correo electrónico','Admin Notices'=>'Avisos al administrador','Updates, announcements, marketing, no spam'=>'Actualizaciones, anuncios, marketing, sin spam','Plugin status & settings'=>'Estado y ajustes del plugin','Active, Deactivated, installed version and settings'=>'Activo, desactivado, versión instalada y ajustes','Privacy Policy'=>'Politica de privacidad','Terms of Service'=>'Términos de servicio','Support'=>'Soporte','Documentation'=>'Documentación','Add Extra AI Words'=>'Agregar palabras extra de IA','Optimize TranslatePress database tables'=>'Optimizar las tablas de la base de datos de TranslatePress','<strong>IMPORTANT NOTE:</strong> Before performing this action it is strongly recommended to first backup the database.'=>'<strong>NOTA IMPORTANTE:</strong> Antes de realizar esta acción, se recomienda encarecidamente hacer primero una copia de seguridad de la base de datos.','IMPORTANT: It is strongly recommended to first backup the database!! Are you sure you want to continue?'=>'IMPORTANTE: ¡¡Se recomienda encarecidamente hacer primero una copia de seguridad de la base de datos!! ¿Seguro que quieres continuar?','Operations to perform'=>'Operaciones a realizar','Remove CDATA for original and dictionary strings'=>'Eliminar CDATA de las cadenas originales y de diccionario','Removes CDATA from trp_original_strings and trp_dictionary_* tables.<br>This type of content should not be detected by TranslatePress. It might have been introduced in the database in older versions of the plugin.'=>'Elimina CDATA de las tablas trp_original_strings y trp_dictionaryo_*. <br>Este tipo de contenido no debería detectarlo TranslatePress. Podría haberse introducido en la base de datos en versiones anteriores del plugin.','Remove untranslated links from dictionary tables'=>'Eliminar enlaces sin traducir de las tablas de diccionario','Removes untranslated links and images from all trp_dictionary_* tables. These tables contain translations for user-inputted strings such as post content, post title, menus etc.'=>'Elimina enlaces e imágenes sin traducir de todas las tablas trp_dictionary_*. Estas tablas contienen traducciones de cadenas introducidas por usuarios, como contenido de la entrada, título de la entrada, menús, etc.','Remove duplicate rows for gettext strings'=>'Eliminar filas duplicadas para las cadenas de Gettext','Cleans up all trp_gettext_* tables of duplicate rows. These tables contain translations for themes and plugin strings.'=>'Limpia las filas duplicadas en todas las tablas trp_gettext_*. Estas tablas contienen traducciones para las cadenas de temas y plugins.','Remove duplicate rows for dictionary strings'=>'Eliminar filas duplicadas para las cadenas de diccionario','Cleans up all trp_dictionary_* tables of duplicate rows. These tables contain translations for user-inputted strings such as post content, post title, menus etc.'=>'Limpia las filas duplicadas en todas las tablas trp_dictionary_*. Estas tablas contienen traducciones para las cadenas ingresadas por el usuario, como el contenido de la entrada, el título de la entrada, los menús, etc.','Remove duplicate rows for original dictionary strings'=>'Eliminar cadenas duplicada para las cadenas de diccionario originales','Cleans up all trp_original_strings table of duplicate rows. This table contains strings in the default language, without any translation.<br>The trp_original_meta table, which contains meta information that refers to the post parent’s ID, is also regenerated.<br>Such duplicates can appear in exceptional situations of unexpected behavior.'=>'Limpia la tabla trp_original_strings de filas duplicadas. Esta tabla contiene cadenas en el idioma predeterminado, sin ninguna traducción.<br>La tabla trp_original_meta, que contiene información meta que hace referencia al ID de la entrada principal, también se regenera.<br>Estos duplicados pueden aparecer en situaciones excepcionales de comportamiento inesperado.','Replace gettext strings that have original ID NULL with the correct original IDs'=>'Reemplazar cadenas Gettext cuyo ID original es NULL por los ID originales correctos','Fixes an edge case issue where some gettext strings have the original ID incorrectly set to NULL, causing problems in the Translation Editor.<br>This operation corrects the original IDs in the trp_gettext_* tables.<br>Only check this option if you encountered an issue in the Translation Editor where clicking the green pencil did not bring up the gettext string for translation in the left sidebar.<br>Otherwise, please leave this option unchecked because it\'s an intensive operation.'=>'Corrige un problema de caso borde donde algunas cadenas Gettext tienen el ID original establecido incorrectamente como NULL, causando problemas en el Editor de traducciones.<br>Esta operación corrige los ID originales en las tablas trp_gettext_*.<br>Marca esta opción solo si encontraste un problema en el Editor de traducciones donde hacer clic en el lápiz verde no mostraba la cadena Gettext para traducir en la barra lateral izquierda.<br>De lo contrario, deja esta opción desmarcada porque es una operación intensiva.','Optimize Database'=>'Optimizar la base de datos','TranslatePress Database Updater'=>'Actualizador de la base de datos de TranslatePress','Updating TranslatePress tables. Please leave this window open.'=>'Actualizando las tablas de TranslatePress. Por favor, deja abierta esta ventana.','The inactive languages will still be visible and active for the admin. For other users they won\'t be visible in the language switchers and won\'t be accessible either.'=>'Los idiomas inactivos seguirán siendo visibles y activos para el administrador. Para otros usuarios no serán visibles en los selectores de idioma ni estarán accesibles.','unknown'=>'desconocido','<strong>Extra Languages add-on</strong> requires TranslatePress version %1$s or higher. You are currently using version %2$s. Please update TranslatePress to enable this feature.'=>'<strong>Complemento Extra Languages</strong> requiere TranslatePress versión %1$s o superior. Actualmente estás usando la versión %2$s. Actualiza TranslatePress para habilitar esta función.','Automatic and manual slug translation changes performed when <strong>TranslatePress - Multilingual</strong> 2.8.4 was active had to be removed because of some issues with that version. All slug translations from before that version are now in use. Thank you for understanding!'=>'Los cambios automáticos y manuales de traducción de slug realizados cuando <strong>TranslatePress - Multilingüe</strong> 2.8.4 estaba activo tuvieron que ser eliminados debido a algunos problemas con esa versión. Ahora se utilizan todas las traducciones de slug anteriores a esa versión. Gracias por tu comprensión.','If you absolutely need them, the removed translations can be found in tables trp_slug_original_obsolete and trp_slug_translation_obsolete.'=>'Si de verdad las necesitas, las traducciones eliminadas se encuentran en las tablas trp_slug_original_obsolete y trp_slug_translation_obsolete.','View Docs'=>'Ver documentación','Assign different domains or subdomains to each language. When visitors access these domains, TranslatePress loads the appropriate language translation directly without redirecting.'=>'Asigna dominios o subdominios diferentes a cada idioma. Cuando los visitantes acceden a estos dominios, TranslatePress carga directamente la traducción del idioma correspondiente sin redirigir.','Example: %1$s for English, %2$s for Spanish, %3$s for French.'=>'Ejemplo: %1$s para inglés, %2$s para español, %3$s para francés.','Before enabling:'=>'Antes de habilitar:','Ensure your domains are registered, pointed to your server, and have SSL certificates configured.'=>'Asegúrate de que tus dominios estén registrados, apuntados a tu servidor y tengan certificados SSL configurados.','Domain'=>'Dominio','Map this language to a different domain or sub-domain.'=>'Asigna este idioma a un dominio o subdominio diferente.','https://example.com'=>'https://example.com','Prefill with current domain'=>'Rellenar con el dominio actual','Check DNS'=>'Verificar DNS','Checking DNS...'=>'Verificando DNS...','DNS is correctly configured!'=>'¡El DNS está configurado correctamente!','DNS check failed. Please verify your domain configuration.'=>'La verificación de DNS falló. Verifica la configuración de tu dominio.','This domain is already assigned to another language.'=>'Este dominio ya está asignado a otro idioma.','<strong>Different Domain per Language add-on</strong> requires TranslatePress version %1$s or higher. You are currently using version %2$s. Please update TranslatePress to enable this feature.'=>'<strong>Complemento Different Domain per Language</strong> requiere TranslatePress versión %1$s o superior. Actualmente estás usando la versión %2$s. Actualiza TranslatePress para habilitar esta función.','Note: This option is disabled when Different Domain for Language addon is active.'=>'Nota: Esta opción se desactiva cuando el complemento Different Domain for Language está activo.','Different Domain per Language: Domain is required when domain mapping is enabled. The toggle has been disabled for languages with empty domains.'=>'Different Domain per Language: Se requiere un dominio cuando la asignación de dominios está habilitada. El interruptor se ha desactivado para los idiomas con dominios vacíos.','Different Domain per Language: The same domain cannot be assigned to multiple languages. The toggle has been disabled for duplicate domains.'=>'Dominio diferente por idioma: El mismo dominio no puede asignarse a varios idiomas. Se ha desactivado el interruptor para los dominios duplicados.','Different Domain per Language: A language domain cannot be the same as the main site URL. The toggle has been disabled for the matching domain.'=>'Dominio diferente por idioma: El dominio de un idioma no puede ser el mismo que la URL del sitio principal. Se ha desactivado el interruptor para el dominio coincidente.','Please enter a domain.'=>'Ingresa un dominio.','Invalid domain format.'=>'Formato de dominio no válido.','Could not reach domain: %s'=>'No se pudo acceder al dominio: %s','Domain returned HTTP status %d.'=>'El dominio devolvió el estado HTTP %d.','Domain is reachable!'=>'¡El dominio es accesible!','Limit this menu item to the following languages'=>'Limita este elemento del menú a los siguientes idiomas','Date format'=>'Formato de fecha','Customize the date formatting per each translated language.<br/>Leave empty for default WP setting or see more information <a href="https://wordpress.org/support/article/formatting-date-and-time/" title="Formatting Date and Time" target="_blank">here</a>'=>'Personaliza el formato de fecha para cada idioma traducido.<br/>Déjalo en blanco para usar el ajuste de WordPress por defecto u obtén más información <a href="https://cl.wordpress.org/support/article/formatting-date-and-time/" title="Formato de fecha y hora" target="_blank">aquí</a>','To edit an existing TranslatePress language, input the language code and fill in only the columns you want to overwrite (e.g. Language name, Flag).<br>You can also add new custom languages. They will be available under General settings, All Languages list, where the URL slug can be edited.'=>'Para editar un idioma existente de TranslatePress, ingresa el código del idioma y completa solo las columnas que quieres sobrescribir (p. ej., Nombre del idioma, Bandera).<br>También puedes agregar nuevos idiomas personalizados. Estarán disponibles en Ajustes generales, lista de todos los idiomas, donde se puede editar el slug de la URL.','For custom flag, first upload the image in media library then paste the URL.<br>Changing or deleting a custom language will impact translations and site URL\'s.<br>The Language code and the ISO Code should contain only alphabetical values, numerical values, "-" and "_".<br>The ISO Codes can be found on <a href = "https://cloud.google.com/translate/docs/languages" target = "_blank">Google ISO Codes</a> and <a href = "https://www.deepl.com/docs-api/translating-text/" target = "_blank">DeepL Target Codes</a>.'=>'Para una bandera personalizada, primero sube la imagen a la biblioteca de medios y luego pega la URL.<br>Cambiar o eliminar un idioma personalizado afectará las traducciones y las URL del sitio.<br>El código de idioma y el código ISO deben contener solo valores alfabéticos, valores numéricos, «-» y «_».<br>Los códigos ISO se pueden encontrar en <a href = "https://cloud.google.com/translate/docs/languages" target = "_blank">Códigos ISO de Google</a> y <a href = "https://www.deepl.com/docs-api/translating-text/" target = "_blank">Códigos de destino de DeepL</a>.','Language code'=>'Código de idioma','Language name'=>'Nombre de idioma','Native name'=>'Nombre nativo','ISO Code'=>'Código ISO','Flag URL'=>'URL de bandera','Text RTL'=>'Texto de derecha a izquierda','Custom language'=>'Idioma personalizado','Disable dynamic translation'=>'Desactivar la traducción dinámica','It disables detection of strings displayed dynamically using JavaScript. <br/>Strings loaded via a server side AJAX call will still be translated.'=>'Desactiva la detección de cadenas mostradas de manera dinámica mediante JavaScript. <br/>Todavía se traducirán las cadenas cargadas mediante llamada AJAX del lado del servidor.','Disable translation for gettext strings'=>'Desactivar traducción para las cadenas gettext','Gettext Strings are strings outputted by themes and plugins. <br> Translating these types of strings through TranslatePress can be unnecessary if they are already translated using the .po/.mo translation file system.<br>Enabling this option can improve the page load performance of your site in certain cases. The disadvantage is that you can no longer edit gettext translations using TranslatePress, nor benefit from automatic translation on these strings.'=>'Las cadenas Gettext son cadenas emitidas por temas y plugins. <br> Traducir este tipo de cadenas a través de TranslatePress puede ser innecesario si ya están traducidas utilizando el sistema de archivos de traducción .po/.mo.<br>Activar esta opción puede mejorar el rendimiento de carga de la página de tu sitio en determinados casos. La desventaja es que ya no puedes editar las traducciones gettext mediante TranslatePress, ni beneficiarte de la traducción automática de estas cadenas.','Gettext Strings translation is disabled'=>'La traducción de cadenas de gettext está desactivada','To enable it go to '=>'Para activarlo ve a ','TranslatePress->Advanced Settings->Debug->Disable translation for gettext strings'=>'TranslatePress->Ajustes avanzados->Depuración->Desactivar traducción de cadenas gettext',' and uncheck the Checkbox.'=>' y desmarca la casilla de verificación.','Dismiss'=>'Descartar','Exclude translated links from sitemap'=>'Excluir del mapa del sitio los enlaces traducidos','Do not include translated links in sitemaps generated by SEO plugins.<br/>Requires <a href="https://translatepress.com/docs/addons/seo-pack/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=miscellaneous" title="TranslatePress Add-on SEO Pack documentation" target="_blank"> SEO Pack Add-on</a> to be installed and activated.'=>'No incluir enlaces traducidos en los sitemaps generados por plugins de SEO.<br/>Requiere que el <a href="https://translatepress.com/docs/addons/seo-pack/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=miscellaneous" title="Documentación del complemento SEO Pack de TranslatePress" target="_blank"> complemento SEO Pack</a> esté instalado y activado.','Disable post container tags for post title'=>'Desactivar etiquetas de contenedor de entrada para el título de la entrada','It disables search indexing the post title in translated languages.<br/>Useful when the title of the post doesn\'t allow HTML thus breaking the page.'=>'Desactiva la indización en buscadores del título de la entrada en los idiomas traducidos.<br/>Útil cuando el título de la entrada no permite HTML, algo que rompe la página.','Disable post container tags for post content'=>'Desactivar etiquetas de contenedor de entrada para el contenido de la entrada','It disables search indexing the post content in translated languages.<br/>Useful when the content of the post doesn\'t allow HTML thus breaking the page.'=>'Desactiva la indización en buscadores del contenido de la entrada en los idiomas traducidos.<br/>Útil cuando el contenido de la entrada no permite HTML, algo que rompe la página.','Do not translate certain paths'=>'No traducir determinadas rutas','Choose what paths can be translated. Supports wildcard at the end of the path.<br>For example, to exclude https://example.com/some/path you can either use the rule /some/path/ or /some/*.<br>Enter each rule on it\'s own line. To exclude the home page use {{home}}.'=>'Elige qué rutas pueden traducirse. Compatible con el uso del carácter comodín al final de la ruta.<br>Por ejemplo, para excluir “https://ejemplo.com/alguna/ruta”, puedes usar la regla “/alguna/ruta/” o “/alguna/*”.<br>Escribe cada regla en una misma línea. Para excluir la página de inicio, utiliza {{home}}.','Exclude Paths From Translation'=>'Excluir rutas de la traducción','Translate Only Certain Paths'=>'Traducir solo determinadas rutas','Enable the hreflang x-default tag for language:'=>'Activar la etiqueta hreflang x-default para el idioma:','Enables the hreflang="x-default" for an entire language. See documentation for more details.'=>'Activa hreflang="x-default" para todo un idioma. Consulta la documentación para obtener más detalles.','Translate numbers and numerals'=>'Traducir números y numerales','Enable translation of numbers ( e.g. phone numbers)'=>'Activa la traducción de números (p. ej., números telefónicos).','Selector'=>'Selector','Exclude from dynamic translation'=>'Excluir de la traducción dinámica','Do not dynamically translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being translated using JavaScript.<br/>These strings will still be translated on the server side if possible.'=>'No se traducirán de forma dinámica las cadenas que se encuentren en los nodos HTML que coincidan con estos selectores.<br>Excluye de la traducción mediante JavaScript a todos los nodos HTML hijos que coincidan con estos selectores.<br/>Todavía se traducirán estas cadenas en el lado del servidor, de ser posible.','Gettext String'=>'Cadena de Gettext','Exclude Gettext Strings'=>'Excluir cadenas de Gettext','Exclude these strings from being translated as Gettext strings by TranslatePress. Leave the domain empty to take into account any Gettext string.<br/>Can still be translated through po/mo files.'=>'Excluye estas cadenas de la traducción como cadenas de getttext por parte de TranslatePress. Deja el dominio en blanco para incluir cualquier cadena de Gettext.<br/>Todavía podrán traducirse mediante archivos PO/MO.','Exclude selectors only from automatic translation'=>'Excluir selectores solo de la traducción automática','Do not automatically translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being automatically translated.<br>Manual translation of these strings is still possible.'=>'No se traducirán automáticamente las cadenas que se encuentren en los nodos HTML que coincidan con estos selectores.<br>Excluye de la traducción automática a todos los nodos HTML hijos que coincidan con estos selectores.<br>Todavía será posible la traducción manual de estas cadenas.','Exclude selectors from translation'=>'Excluir selectores de la traducción','Do not translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being translated.<br>These strings cannot be translated manually nor automatically.'=>'No se traducirán las cadenas que se encuentren en los nodos HTML que coincidan con estos selectores.<br>Excluye de la traducción a todos los nodos HTML hijos que coincidan con estos selectores.<br>Estas cadenas no podrán ser traducidas de forma manual o automática.','String'=>'Cadena','Exclude strings from automatic translation'=>'Excluir cadenas de la traducción automática','Do not automatically translate these strings (ex. names, technical words...)<br>Paragraphs containing these strings will still be translated except for the specified part.'=>'No se traducirán automáticamente estas cadenas (p. ej., nombres, vocabulario técnico...).<br>Todavía se traducirán los párrafos que contengan estas cadenas, a excepción de la parte especificada.','Fix broken HTML'=>'Corregir HTML roto','General attempt to fix broken or missing HTML on translated pages.<br/>'=>'Intento general de corregir el HTML roto o faltante en las páginas traducidas.<br/>','Force slash at end of home url:'=>'Forzar barra oblicua al final de la URL de inicio','Ads a slash at the end of the home_url() function'=>'Agrega una barra oblicua ( / ) al final de la función home_url().','Show Both (recommended)'=>'Mostrar ambos (recomendado)','Remove Country Locale'=>'Eliminar la configuración regional del país','Remove Region Independent Locale'=>'Eliminar la configuración regional independiente del idioma local','Remove duplicate hreflang'=>'Eliminar las etiquetas “hreflang” dupilicadas','Choose which hreflang tags will appear on your website.<br/>We recommend showing both types of hreflang tags as indicated by <a href="https://developers.google.com/search/docs/advanced/crawling/localized-versions" title="Google Crawling" target="_blank">Google documentation</a>.<br/>Removing Country Locale when having multiple Country Locales of the same language (ex. English UK and English US) will result in showing one hreflang tag with link to just one of the region locales for that language.'=>'Selecciona qué etiquetas hreflang aparecerán en tu sitio web.<br/>Recomendamos mostrar ambos tipos de etiquetas hreflang según lo indicado en la <a href="https://developers.google.com/search/docs/advanced/crawling/localized-versions" title="Rastreo de Google" target="_blank">documentación de Google</a>.<br/>Al eliminar la localización de país cuando se tienen múltiples localizaciones de país del mismo idioma (ej. inglés del Reino Unido e inglés de Estados Unidos), se mostrará una etiqueta hreflang con un enlace a solo una de las localizaciones regionales de ese idioma.','Default (example: en-US, fr-CA, etc.)'=>'Por defecto (ejemplo: es-ES, fr-CA, etc.)','Regional (example: en, fr, es, etc.)'=>'Regionial (ejemplo: en, fr, es, etc.)','HTML Lang Attribute Format'=>'Formato del atributo lang HTML','Change lang attribute of the html tag to a format that includes country regional or not. <br>In HTML, the lang attribute (<html lang="en-US">)  should be used to  specify the language of text content so that the  browser can correctly display or process  your content (eg. for  hyphenation, styling, spell checking, etc).'=>'Cambia el atributo lang de la etiqueta html a un formato que incluya la región del país o no. <br>En HTML debería usarse el atributo lang (<html lang="es-CL">) específico del idioma del contexto del texto para que el navegador pueda mostrar o procesar correctamente tu contenido (p. ej. para la separación de sílabas, el estilo y la corrección ortográfica, etc.)','Load legacy Language Switcher'=>'Cargar conmutador de idioma heredado','Applies to all types of language switchers (floating, shortcode, and menu). When enabled, the site will revert to using the original Language Switcher configured in the General Settings tab, replacing the new customizable version. Your existing switcher settings will remain saved, but they will be ignored while this option is active.'=>'Se aplica a todos los tipos de conmutadores de idioma (flotante, shortcode y menú). Cuando esté activada, el sitio volverá a utilizar el Conmutador de idioma original configurado en la pestaña Configuración general, sustituyendo a la nueva versión personalizable. Tu configuración existente del conmutador permanecerá guardada, pero será ignorada mientras esta opción esté activa.','Load legacy SEO Pack Add-On'=>'Extensión Load legacy SEO Pack','In case the recent migration to the new slug rewrite is causing trouble, set this to Yes to use the old method <br> Please <a href="https://translatepress.com/support/open-ticket/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=troubleshooting" target="_blank">open a support ticket</a> letting us know of the issues you are having.'=>'En caso de que la migración reciente a la nueva reescritura de slug esté causando problemas, configura esto como Sí para usar el método anterior <br> Por favor, <a href="https://translatepress.com/support/open-ticket/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=troubleshooting" target="_blank">abre un ticket de soporte</a> informándonos de los problemas que estás teniendo.','Manual Translation Only'=>'Solo traducción manual','TranslatePress pro-actively scans and saves strings in the database when users access translated pages. <br>This setting disables this functionality and only allows translation and string saving when inside the Translation Editor. <br>Also disables machine translation outside the Translation Editor, giving you better control over character spending, by translating only the pages you visit in the Translation Editor.'=>'TranslatePress escanea y guarda de forma proactiva cadenas en la base de datos cuando los usuarios acceden a páginas traducidas.<br>Esta configuración deshabilita esta funcionalidad y solo permite traducir y guardar cadenas dentro del Editor de traducción.<br>También deshabilita la traducción automática fuera del Editor de traducción, dándote un mejor control sobre el gasto de caracteres, al traducir solo las páginas que visitas en el Editor de traducción.','Open language switcher only on click'=>'Abrir el conmutador de idioma solo al hacer clic','Open the language switcher shortcode by clicking on it instead of hovering.<br> Close it by clicking on it, anywhere else on the screen or by pressing the escape key. This will affect only the shortcode language switcher.'=>'Abre el conmutador de idioma mediante shortcode haciendo clic en él en lugar de al pasar el cursor.<br>Se cierra haciendo clic en él, en cualquier lugar de la pantalla o presionando la tecla Escape. Solo afectará al conmutador de idioma mediante shortcode.','Show opposite language in the language switcher'=>'Mostrar el idioma opuesto en el conmutador de idioma','Transforms the language switcher into a button showing the other available language, not the current one.<br> Only works when there are exactly two languages, the default one and a translation one.<br>This will affect the shortcode language switcher and floating language switcher as well.<br> To achieve this in menu language switcher go to Appearance->Menus->Language Switcher and select Opposite Language.'=>'Transforma el conmutador de idioma en un botón donde se muestra el otro idioma disponible, no el actual.<br> Solo funciona cuando hay exactamente dos idiomas, el establecido por defecto y el de traducción.<br>También afectará al shortcode del conmutador de idioma y al conmutador flotante de idioma.<br> Para conseguirlo en el conmutador de idioma del menú, ve a Apariencia -> Menús -> Conmutador de idioma y selecciona Idioma opuesto.','<a href="%s">Click here</a> to access the database optimization tool.'=>'<a href="%s">Haz clic aquí</a> para acceder a la herramienta de optimización de la base de datos.','It helps remove possible duplicate translations, clear unnecessary data and repair possible metadata issues.'=>'Ayuda a eliminar posibles traducciones duplicadas, borrar datos innecesarios y reparar posibles problemas de metadatos.','<a href="%s" target="_blank">Here</a> you can observe the last 5 SQL errors relevant to TranslatePress if they exist.'=>'<a href="%s" target="_blank">Aquí</a> puedes observar los 5 últimos errores SQL relevantes para TranslatePress si existen.','Troubleshooting'=>'Diagnóstico','Exclude Gettext strings'=>'Excluir cadenas Gettext','Debug'=>'Depuración','Custom languages'=>'Idiomas personalizados','Miscellaneous options'=>'Miscelánea','Exclude strings & pages'=>'Excluir cadenas y páginas','Automatic Translation Memory'=>'Memoria de traducción automática','Serve same translation for similar text. The strings need to have a percentage of 95% similarity.<br>Helps prevent losing existing translation when correcting typos or making minor adjustments to the original text. <br>If a translation already exists for a very similar original string, it will automatically be used for the current original string.<br>Does not work when making changes to a text that is part of a translation block unless the new text is manually merged again in a translation block.<br>Each string needs to have a minimum of 50 characters.'=>'Sirve la misma traducción para textos similares. Las cadenas deben tener un porcentaje de similitud del 95%.<br>Ayuda a evitar que se pierda la traducción existente al corregir erratas o hacer pequeños ajustes en el texto original. <br>Si ya existe una traducción para una cadena original muy similar, se utilizará automáticamente para la cadena original actual.<br>No funciona cuando se realizan cambios en un texto que forma parte de un bloque de traducción, a menos que el nuevo texto se vuelva a fusionar manualmente en un bloque de traducción.<br>Cada cadena debe tener un mínimo de 50 caracteres.','WARNING: This feature can negatively impact page loading times in secondary languages, particularly with large databases (for example websites with a lot of pages or products). If you experience slow loading times, disable this and try again.'=>'ATENCIÓN: Esta función puede afectar negativamente a los tiempos de carga de las páginas en idiomas secundarios, sobre todo con bases de datos grandes (por ejemplo, sitios web con muchas páginas o productos). Si experimentas tiempos de carga lentos, desactívalo y vuelve a intentarlo.','Fix missing dynamic content'=>'Corregir el contenido dinámico faltante','May help fix missing content inserted using JavaScript. <br> It shows dynamically inserted content in original language for a moment before the translation request is finished.'=>'Puede ayudar a corregir el contenido faltante insertado mediante JavaScript. <br>Muestra momentáneamente el contenido insertado de manera dinámica en el idioma original antes de que finalice la solicitud de traducción.','Filter Gettext wrapping from post content and title'=>'Filtrar envolturas de Gettext del contenido y el título de la entrada','Filters gettext wrapping such as #!trpst#trp-gettext from all updated post content and post title. Does not affect previous post content. <br/><strong>Database backup is recommended before switching on.</strong>'=>'Filtra las envolturas de Gettext, como #!trpst#trp-gettext, de todo el contenido y el título actualizados de la entrada. No afecta al contenido previo de la entrada. <br/><strong>Se recomienda hacer una copia de seguridad de la base de datos antes de activar esta opción.</strong>','Filter Gettext wrapping from post meta'=>'Filtrar envolturas de Gettext del meta de la entrada','Filters gettext wrapping such as #!trpst#trp-gettext from all updated post meta. Does not affect previous post meta. <br/><strong>Database backup is recommended before switching on.</strong>'=>'Filtra las envolturas de Gettext, como #!trpst#trp-gettext, de todo el meta actualizado de la entrada. No afecta al meta previo de la entrada. <br/><strong>Se recomienda hacer una copia de seguridad de la base de datos antes de activar esta opción.</strong>','Google Translate v2'=>'Google Translate v2','Google Translate API Key'=>'Clave de API de Google Translate','Add your API Key here...'=>'Agrega aquí tu clave API...','Visit <a href="https://cloud.google.com/docs/authentication/api-keys" target="_blank">this link</a> to see how you can set up an API key, <strong>control API costs</strong> and set HTTP referrer restrictions.'=>'Visita <a href="https://cloud.google.com/docs/authentication/api-keys" target="_blank">este enlace</a> para conocer cómo puedes configurar una clave de API, <strong>controlar los costes de la API</strong> y establecer restricciones para las referencias HTTP.','Your HTTP referrer is: %s'=>'Tu referencia HTTP es: %s','There was an error on the server processing your Google Translate key.'=>'Hubo un error en el servidor al procesar tu clave de Google Translate.','There was an error with your Google Translate key.'=>'Hubo un error con tu clave de Google Translate.','Please check your TranslatePress license key.'=>'Comprueba tu clave de licencia de TranslatePress.','TranslatePress AI'=>'TranslatePress AI','No Active License Detected for this website.'=>'No se ha detectado ninguna licencia activa para este sitio.','In order to enable Automatic Translation using TranslatePress AI, you need a license key by creating a free account.'=>'Para habilitar la traducción automática usando TranslatePress AI, necesitas una clave de licencia creando una cuenta gratuita.','Create your Free Account'=>'Crea tu cuenta gratuita',' or '=>' o ','Enter your license key'=>'Introduce tu clave de licencia',' Or %1$spurchase one here%2$s'=>' O %1$scompra uno aquí%2$s','Your free account includes: '=>'Tu cuenta gratuita incluye: ','Get more AI Words and unlock all AI features with TranslatePress Pro.'=>'Obtén más palabras de IA y desbloquea todas las funciones de IA con TranslatePress Pro.','You have a valid %s <strong>license</strong>.'=>'Tienes una <strong>licencia</strong> de %s válida.',' words remaining. '=>' palabras restantes. ','Recheck'=>'Volver a comprobar','Rechecking...'=>'Volviendo a comprobar...','Done.'=>'Hecho.','Manage your license & quota on the %s'=>'Gestiona tu licencia y cuota en el %s','TranslatePress.com Account Page'=>'Página de cuenta de TranslatePress.com','SEO support for page slug, page title, description and Facebook and Twitter social graph information. The HTML lang attribute is properly set.'=>'Soporte SEO para slug de página, título de página, descripción e información de social graph de Facebook y Twitter. El atributo lang de HTML está configurado correctamente.','Enable Modules'=>'Habilitar módulos','Enable Add-on modules to extend TranslatePress and enhance the functionality of your translated site.'=>'Habilita los módulos complementarios para extender TranslatePress y mejorar la funcionalidad de tu sitio traducido.','More functionality with TranslatePress Pro.'=>'Más funcionalidad con TranslatePress Pro.','Already a Pro User?'=>'¿Ya eres usuario Pro?','Activate License Key'=>'Activar clave de licencia','This add-on is not available on your current plan.'=>'Este complemento no está disponible en tu plan actual.','Continue'=>'Continuar','The link you followed has expired. Please reload the page and try again.'=>'El enlace que seguiste ha expirado. Por favor, recarga la página e inténtalo de nuevo.','A valid license is required to enable Automatic Translation.'=>'Se requiere una licencia válida para habilitar la Traducción Automática.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=tp-ai">https://translatepress.com/account</a> -> Manage Sites.'=>'Tu clave de licencia está deshabilitada para esta URL. Reactívala desde <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=tp-ai">https://translatepress.com/account</a> -> Administrar sitios.','<p><strong>License key mismatch.</strong> The license you entered doesn\'t match the TranslatePress version you have installed.</p><p>Please check that you\'ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>La clave de licencia no coincide.</strong> La licencia que ingresaste no coincide con la versión de TranslatePress que tienes instalada.</p><p>Por favor, verifica que has instalado la versión correcta para tu licencia desde tu cuenta de TranslatePress.</p>','Automatically translate your website using TranslatePress AI.'=>'Traduce automáticamente tu sitio web usando TranslatePress AI.','In order to enable Automatic Translation using TranslatePress AI, please enter your license key from'=>'Para habilitar la Traducción Automática usando TranslatePress AI, por favor ingresa tu clave de licencia desde','your account.'=>'tu cuenta.','Skip and continue with manual translation »'=>'Saltar y continuar con la traducción manual »','Get Your Free TranslatePress AI License'=>'Obtén tu licencia gratuita de TranslatePress AI','Generate License'=>'Generar licencia','Creating a free account includes: '=>'Crear una cuenta gratuita incluye: ','Are you a TranslatePress PRO user?'=>'¿Eres usuario de TranslatePress PRO?','Install & Activate your pro plugin.'=>'Instala y activa tu plugin pro.','Skip this step'=>'Saltar este paso','The email address you added is incorrect.'=>'La dirección de correo electrónico que ingresaste es incorrecta.','Setup Complete'=>'Configuración completada','You\'re ready to start translating!'=>'¡Estás listo para empezar a traducir!','You have successfully set up TranslatePress for your website.'=>'Configuraste TranslatePress exitosamente para tu sitio web.','Receive '=>'Recibe ','Yes, send me multilingual growth ti